import{c as i,Q as a,j as e,m as t}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"设计模式系列目录","description":"","frontmatter":{},"headers":[],"relativePath":"../designPatternLearning/目录.md","filePath":"../designPatternLearning/目录.md","lastUpdated":1779015580000}'),o={name:"../designPatternLearning/目录.md"};function r(s,l,n,h,d,c){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="设计模式系列目录" tabindex="-1">设计模式系列目录 <a class="header-anchor" href="#设计模式系列目录" aria-label="Permalink to &quot;设计模式系列目录&quot;">​</a></h1><h2 id="系列定位" tabindex="-1">系列定位 <a class="header-anchor" href="#系列定位" aria-label="Permalink to &quot;系列定位&quot;">​</a></h2><p>这是一套面向业务开发、框架开发和架构重构的设计模式学习目录。</p><p>它回答的问题不是&quot;单例模式定义是什么&quot;,而是:</p><ul><li>为什么同一段业务代码改几次之后会变得越来越难维护</li><li>什么时候应该抽象,什么时候应该忍住</li><li>GoF 设计模式和 MVC / MVVM 这类应用架构模式有什么区别</li><li>为什么同一个模式在 Java、Go、Rust、TypeScript 里长得不一样</li><li>代码评审时如何判断一个模式是必要设计还是过度设计</li></ul><h2 id="大纲目录" tabindex="-1">大纲目录 <a class="header-anchor" href="#大纲目录" aria-label="Permalink to &quot;大纲目录&quot;">​</a></h2><h3 id="第一层-心智与基础" tabindex="-1">第一层:心智与基础 <a class="header-anchor" href="#第一层-心智与基础" aria-label="Permalink to &quot;第一层:心智与基础&quot;">​</a></h3><ol><li>设计模式总览:模式不是背诵题,是变化管理工具</li><li>UML 与代码结构图速通:类图、依赖、组合、聚合、时序图</li><li>SOLID 原则:哪些有用,哪些容易被误解</li><li>组合优于继承:复用、扩展点与抽象层的真实代价</li><li>依赖倒置与依赖注入:从 new 到 IoC 容器</li></ol><h3 id="第二层-创建型模式" tabindex="-1">第二层:创建型模式 <a class="header-anchor" href="#第二层-创建型模式" aria-label="Permalink to &quot;第二层:创建型模式&quot;">​</a></h3><ol start="6"><li>单例模式:全局唯一、生命周期与测试噩梦</li><li>工厂方法与抽象工厂:把创建逻辑从业务里拔出来</li><li>建造者模式:复杂对象、可读参数与不可变配置</li><li>原型模式:复制对象、快照与模板化创建</li><li>对象池与资源池:连接池、线程池与复用边界</li></ol><h3 id="第三层-结构型模式" tabindex="-1">第三层:结构型模式 <a class="header-anchor" href="#第三层-结构型模式" aria-label="Permalink to &quot;第三层:结构型模式&quot;">​</a></h3><ol start="11"><li>适配器模式:旧接口、新接口与第三方 SDK 包装</li><li>装饰器模式:不改原类也能叠能力</li><li>代理模式:远程代理、缓存代理、权限代理与 AOP</li><li>外观模式:给复杂子系统一个稳定入口</li><li>组合模式:树形结构、菜单、文件系统与 UI 组件</li><li>桥接模式:两个维度独立变化时怎么拆</li><li>享元模式:大量小对象的内存优化</li></ol><h3 id="第四层-行为型模式" tabindex="-1">第四层:行为型模式 <a class="header-anchor" href="#第四层-行为型模式" aria-label="Permalink to &quot;第四层:行为型模式&quot;">​</a></h3><ol start="18"><li>策略模式:消灭 if-else,但别制造类爆炸</li><li>模板方法模式:框架钩子、生命周期与反向控制</li><li>观察者模式:事件、订阅、响应式与内存泄漏</li><li>发布订阅模式:EventBus、消息队列与观察者的边界</li><li>命令模式:撤销、重做、队列化与操作日志</li><li>状态模式:把状态机从 if-else 里救出来</li><li>责任链模式:中间件、过滤器、审批流与错误传播</li><li>迭代器模式:遍历协议、惰性序列与流式处理</li><li>访问者模式:AST、编译器 Pass 与表达式问题</li><li>解释器模式:DSL、小语言与规则引擎的边界</li></ol><h3 id="第五层-应用架构模式" tabindex="-1">第五层:应用架构模式 <a class="header-anchor" href="#第五层-应用架构模式" aria-label="Permalink to &quot;第五层:应用架构模式&quot;">​</a></h3><ol start="28"><li>MVC:Model、View、Controller 到底分什么</li><li>MVP:Presenter 为什么适合测试,又为什么少见了</li><li>MVVM:ViewModel、数据绑定与响应式 UI</li><li>分层架构:Controller / Service / Repository 的边界</li><li>六边形架构:端口、适配器与业务核心保护</li><li>Clean Architecture:用例层、实体层与依赖规则</li><li>DDD 战术模式:Entity、Value Object、Aggregate、Repository</li><li>CQRS:读写模型分离,不是所有系统都需要</li><li>事件驱动架构:领域事件、集成事件与最终一致性</li><li>微服务模式:服务拆分、Saga、API Gateway 与反腐层</li></ol><h3 id="第六层-前端与客户端模式" tabindex="-1">第六层:前端与客户端模式 <a class="header-anchor" href="#第六层-前端与客户端模式" aria-label="Permalink to &quot;第六层:前端与客户端模式&quot;">​</a></h3><ol start="38"><li>组件模式:Props、Slots、Composition 与复用边界</li><li>单向数据流:Flux / Redux / Elm 架构的核心约束</li><li>响应式模式:Observable、Signals、Computed 与副作用</li><li>状态管理模式:本地状态、服务端状态、全局状态怎么分</li><li>容器组件与展示组件:什么时候有用,什么时候过时</li><li>Hooks / Composable 模式:逻辑复用的新默认</li><li>路由与页面模式:嵌套路由、布局、加载器与守卫</li><li>微前端模式:模块联邦、沙箱、路由隔离与组织边界</li></ol><h3 id="第七层-工程判断与反模式" tabindex="-1">第七层:工程判断与反模式 <a class="header-anchor" href="#第七层-工程判断与反模式" aria-label="Permalink to &quot;第七层:工程判断与反模式&quot;">​</a></h3><ol start="46"><li>重构到模式:从坏味道开始,不要从模式开始</li><li>常见反模式:上帝对象、贫血模型、过度抽象、回调地狱</li><li>模式与语言特性:Java、Go、Rust、TypeScript 写法为什么不同</li><li>模式选型清单:需求变化点、团队能力、测试成本与性能约束</li><li>设计模式面试与真实代码评审:怎么讲清取舍,不背模板</li></ol><h2 id="最小阅读路径" tabindex="-1">最小阅读路径 <a class="header-anchor" href="#最小阅读路径" aria-label="Permalink to &quot;最小阅读路径&quot;">​</a></h2><p>只想理解 MVC / MVVM 和业务代码分层:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 03 -&gt; 04 -&gt; 05 -&gt; 18 -&gt; 20 -&gt; 28 -&gt; 29 -&gt; 30 -&gt; 31 -&gt; 32 -&gt; 38 -&gt; 39 -&gt; 41</span></span></code></pre></div><p>想系统补 GoF 模式:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 02 -&gt; 03 -&gt; 06-27 -&gt; 46 -&gt; 48 -&gt; 49</span></span></code></pre></div>',25)])])}const g=i(o,[["render",r]]);export{u as __pageData,g as default};
